import asyncio
import json
import uuid
from dataclasses import dataclass, field
from typing import Dict, Set, Optional, Any, List

import websockets
from websockets.server import WebSocketServerProtocol


@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str


@dataclass
class Player:
    player_id: str
    websocket: WebSocketServerProtocol
    inventory: Set[str] = field(default_factory=set)
    lock: asyncio.Lock = field(default_factory=asyncio.Lock)


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.global_lock = asyncio.Lock()

    async def register(self, websocket: WebSocketServerProtocol, player_id: str) -> Player:
        async with self.global_lock:
            player = Player(player_id=player_id, websocket=websocket)
            self.players[player_id] = player
            return player

    async def unregister(self, player_id: str):
        async with self.global_lock:
            self.players.pop(player_id, None)

    async def create_item(self, owner_id: str, name: str) -> Item:
        async with self.global_lock:
            item = Item(item_id=str(uuid.uuid4()), name=name, owner_id=owner_id)
            self.items[item.item_id] = item
            if owner_id in self.players:
                self.players[owner_id].inventory.add(item.item_id)
            return item

    async def handle_message(self, player: Player, message: Dict[str, Any]):
        action = message.get("action")

        if action == "create_item":
            name = message.get("name")
            if not name:
                await self.send_error(player.websocket, "Missing item name")
                return
            item = await self.create_item(player.player_id, name)
            await self.send_json(player.websocket, {
                "type": "item_created",
                "item": {"item_id": item.item_id, "name": item.name, "owner_id": item.owner_id},
            })
            return

        if action == "trade_item":
            item_id = message.get("item_id")
            target_id = message.get("target_id")
            if not item_id or not target_id:
                await self.send_error(player.websocket, "Missing item_id or target_id")
                return
            await self.trade_item(player.player_id, target_id, item_id)
            return

        if action == "inventory":
            await self.send_json(player.websocket, {
                "type": "inventory",
                "items": await self.get_inventory(player.player_id),
            })
            return

        await self.send_error(player.websocket, f"Unknown action: {action}")

    async def get_inventory(self, player_id: str) -> List[Dict[str, Any]]:
        async with self.global_lock:
            player = self.players.get(player_id)
            if not player:
                return []
            items = []
            for item_id in player.inventory:
                item = self.items.get(item_id)
                if item:
                    items.append({"item_id": item.item_id, "name": item.name, "owner_id": item.owner_id})
            return items

    async def trade_item(self, from_player_id: str, to_player_id: str, item_id: str):
        if from_player_id == to_player_id:
            return

        first_id, second_id = sorted([from_player_id, to_player_id])

        async with self.global_lock:
            from_player = self.players.get(from_player_id)
            to_player = self.players.get(to_player_id)
            item = self.items.get(item_id)

            if not from_player or not to_player:
                if from_player:
                    await self.send_error(from_player.websocket, "Trade failed: player not found")
                return

            if not item:
                await self.send_error(from_player.websocket, "Trade failed: item not found")
                return

            async with from_player.lock:
                async with to_player.lock:
                    if item.owner_id != from_player_id:
                        await self.send_error(from_player.websocket, "Trade failed: you do not own this item")
                        return

                    if item_id not in from_player.inventory:
                        await self.send_error(from_player.websocket, "Trade failed: item not in inventory")
                        return

                    from_player.inventory.remove(item_id)
                    to_player.inventory.add(item_id)
                    item.owner_id = to_player_id

                    await self.send_json(from_player.websocket, {
                        "type": "trade_result",
                        "status": "ok",
                        "item_id": item_id,
                        "new_owner_id": to_player_id,
                    })
                    await self.send_json(to_player.websocket, {
                        "type": "item_received",
                        "item": {"item_id": item.item_id, "name": item.name, "owner_id": item.owner_id},
                    })

    async def send_json(self, websocket: WebSocketServerProtocol, data: Dict[str, Any]):
        try:
            await websocket.send(json.dumps(data))
        except Exception:
            pass

    async def send_error(self, websocket: WebSocketServerProtocol, message: str):
        await self.send_json(websocket, {"type": "error", "message": message})


server = GameServer()


async def handler(websocket: WebSocketServerProtocol):
    player: Optional[Player] = None
    try:
        raw = await websocket.recv()
        hello = json.loads(raw)
        if hello.get("action") != "login" or not hello.get("player_id"):
            await websocket.send(json.dumps({"type": "error", "message": "First message must be login with player_id"}))
            return

        player_id = str(hello["player_id"])
        player = await server.register(websocket, player_id)
        await websocket.send(json.dumps({"type": "login_ok", "player_id": player_id}))

        async for raw_message in websocket:
            try:
                message = json.loads(raw_message)
            except json.JSONDecodeError:
                await server.send_error(websocket, "Invalid JSON")
                continue
            await server.handle_message(player, message)

    except websockets.ConnectionClosed:
        pass
    finally:
        if player:
            await server.unregister(player.player_id)


async def main():
    async with websockets.serve(handler, "0.0.0.0", 8765):
        await asyncio.Future()


if __name__ == "__main__":
    asyncio.run(main())